exercises.solution:
function loadConfig(env) {
  const errors = [];
  const port = parseInt(env.PORT, 10) || 3000;
  const dbUrl = env.DATABASE_URL;
  const jwtSecret = env.JWT_SECRET;

  if (!dbUrl) errors.push('DATABASE_URL is required');
  if (!jwtSecret) errors.push('JWT_SECRET is required');
  else if (jwtSecret.length < 16) errors.push('JWT_SECRET must be at least 16 characters');

  if (errors.length > 0) {
    throw new Error('Config validation failed: ' + errors.join('; '));
  }

  return { port, dbUrl, jwtSecret };
}

// Valid config
try {
  const config = loadConfig({ DATABASE_URL: 'pg://localhost/db', JWT_SECRET: 'a-secret-thats-long-enough' });
  console.log('Valid:', config);
} catch (e) { console.log(e.message); }

// Missing fields
try {
  loadConfig({});
} catch (e) { console.log('Missing:', e.message); }

// Short secret
try {
  loadConfig({ DATABASE_URL: 'pg://localhost/db', JWT_SECRET: 'short' });
} catch (e) { console.log('Short:', e.message); }

