function auditApp(config) {
  const checks = {
    hasHelmet: 'Helmet security headers',
    hasCors: 'CORS configuration',
    hasRateLimit: 'Rate limiting',
    hasErrorHandler: 'Error handling middleware',
    hasHealthCheck: 'Health check endpoint',
    hasLogging: 'Request logging'
  };

  const missing = [];
  let score = 0;

  for (const [key, label] of Object.entries(checks)) {
    if (config[key]) {
      score++;
    } else {
      missing.push(label);
    }
  }

  return {
    score,
    total: Object.keys(checks).length,
    missing,
    ready: score === Object.keys(checks).length
  };
}

const result = auditApp({
  hasHelmet: true, hasCors: true, hasRateLimit: false,
  hasErrorHandler: true, hasHealthCheck: false, hasLogging: true
});

console.log('Score:', result.score + '/' + result.total);
console.log('Ready:', result.ready);
console.log('Missing:', result.missing);

